CREATE TABLE `tournament` (
  `id` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sportType` enum('FUTBOL_11','FUTSAL','FUTBOL_7','FUTBOL_SALA','BALONMANO','BALONCESTO','VOLEY','VOLEY_PLAYA','TENIS_MESA','TENIS','BEACH_TENNIS','AJEDREZ','ATLETISMO','DEPORTE_GENERICO','DISPAROS','BATTLE_ROYALE','MOBA_LOL','MOBA_DOTA') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` enum('DRAFT','REGISTRATION_OPEN','IN_PROGRESS','COMPLETED','CANCELLED') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'DRAFT',
  `format` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'liga',
  `startDate` datetime(3) NOT NULL,
  `endDate` datetime(3) NOT NULL,
  `registrationEnd` datetime(3) DEFAULT NULL,
  `maxTeams` int NOT NULL DEFAULT '16',
  `minPlayers` int NOT NULL DEFAULT '7',
  `maxPlayersPerTeam` int NOT NULL DEFAULT '22',
  `logo` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `banner` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `customUrl` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `plan` enum('PEQUENO','INTERMEDIARIO','GRANDE','PROFESIONAL') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PEQUENO',
  `maxPlayersLimit` int NOT NULL DEFAULT '300',
  `maxSponsors` int NOT NULL DEFAULT '3',
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  `organizerId` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `classificationCriteria` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PUNTOS,GOLES,GOLES_A_FAVOR,RESULTADOS_ENTRE_SI,TARJETAS_AMARILLAS,TARJETAS_ROJAS,W_O',
  `phaseSystem` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'TODOS_CONTRA_TODOS',
  `themeColor` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT '#FF6B00',
  `contact` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `location` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `prizes` text COLLATE utf8mb4_unicode_ci,
  `rules` text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  UNIQUE KEY `Tournament_customUrl_key` (`customUrl`),
  KEY `Tournament_organizerId_fkey` (`organizerId`)
) ENGINE=MyISAM DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
